INSERT INTO public.audit_logs (id, actor_user_id, action_type, entity_type, entity_id, target_label, summary, reason, request_id, ip_address, user_agent, before_snapshot_json, after_snapshot_json, created_at) VALUES (385, 'cmmuhzgov000040g9nxeekhj6', 'UPDATE', 'Article', '21', '10 Idées Déco Révolutionnaires et Inspirantes avec le Carrelage Effet Bois : Transformez Votre Intérieur Sans Vous Ruiner', 'Mise a jour d''un article', NULL, NULL, NULL, NULL, '{"id": 21, "slug": "10-idees-deco-revolutionnaires-et-inspirantes-avec-le-carrelage-effet-bois", "title": "10 Idées Déco Révolutionnaires et Inspirantes avec le Carrelage Effet Bois : Transformez Votre Intérieur Sans Vous Ruiner", "author": {"id": "cmmuhzgov000040g9nxeekhj6", "email": "root@cobamgroup.com", "status": "ACTIVE", "profile": {"lastName": "Zlitni", "firstName": "Baha"}, "powerType": "ROOT", "receivedRoleAssignments": []}, "status": "PUBLISHED", "content": "{\"type\":\"doc\",\"content\":[{\"type\":\"heading\",\"attrs\":{\"level\":1},\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"textStyle\",\"attrs\":{\"color\":\"#0a8dc1\"}},{\"type\":\"bold\"}],\"text\":\"10 Idées Déco Révolutionnaires et Inspirantes avec le Carrelage Effet Bois : Transformez Votre Intérieur Sans Vous Ruiner\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Il y a quelques mois, un couple venait de rénover son salon. Comme beaucoup, ils hésitaient : parquet ou carrelage ? Le charme du bois les séduisait, mais l’entretien et le prix les freinaient. Finalement, ils ont choisi le \"},{\"type\":\"text\",\"marks\":[{\"type\":\"link\",\"attrs\":{\"href\":\"https://cobamgroup.com/?s=carrelage&post_type=product\",\"target\":\"_blank\",\"rel\":\"noopener noreferrer nofollow\",\"class\":null,\"title\":null}},{\"type\":\"bold\"}],\"text\":\"carrelage\"},{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\" effet bois. Résultat : une pièce chaleureuse, facile à vivre et à entretenir. Le plus drôle ? À chaque visite, leurs amis s’exclament : \"},{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"},{\"type\":\"italic\"}],\"text\":\"« C’est du vrai parquet ? »\"},{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\" Et eux de sourire : \"},{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"},{\"type\":\"italic\"}],\"text\":\"« Non, c’est encore mieux. »\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Chez \"},{\"type\":\"text\",\"marks\":[{\"type\":\"link\",\"attrs\":{\"href\":\"https://cobamgroup.com/\",\"target\":\"_blank\",\"rel\":\"noopener noreferrer nofollow\",\"class\":null,\"title\":null}},{\"type\":\"bold\"}],\"text\":\"COBAM Group\"},{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\", nous accompagnons nos clients dans leurs projets déco depuis des années. Que ce soit dans nos showrooms ou sur les chantiers, nous savons qu’un carrelage effet bois bien choisi transforme radicalement l’atmosphère d’un habitat. Voici notre guide complet, adapté aux réalités du climat tunisien.\"}]},{\"type\":\"heading\",\"attrs\":{\"level\":2},\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Pourquoi le Carrelage Effet Bois Fait-il Fureur en 2025 ?\"}]},{\"type\":\"table\",\"content\":[{\"type\":\"tableRow\",\"content\":[{\"type\":\"tableHeader\",\"attrs\":{\"colspan\":1,\"rowspan\":1,\"colwidth\":null},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Avantage\"}]}]},{\"type\":\"tableHeader\",\"attrs\":{\"colspan\":1,\"rowspan\":1,\"colwidth\":null},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Bénéfice concret\"}]}]}]},{\"type\":\"tableRow\",\"content\":[{\"type\":\"tableCell\",\"attrs\":{\"colspan\":1,\"rowspan\":1,\"colwidth\":null},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}