INSERT INTO public.audit_logs (id, actor_user_id, action_type, entity_type, entity_id, target_label, summary, reason, request_id, ip_address, user_agent, before_snapshot_json, after_snapshot_json, created_at) VALUES (600, 'cmmuhzgov000040g9nxeekhj6', 'UPDATE', 'Article', '22', 'Entretien du marbre poli : Secrets Pro Infaillibles pour une Brillance Éternelle', 'Mise à jour d''un article', NULL, NULL, NULL, NULL, '{"id": 22, "slug": "les-secrets-pro-infaillibles-pour-une-brillance-eternelle", "title": "Entretien du marbre poli : Secrets Pro Infaillibles pour une Brillance Éternelle", "author": {"id": "cmmuhzgov000040g9nxeekhj6", "email": "root@cobamgroup.com", "status": "ACTIVE", "profile": {"lastName": "Zlitni", "firstName": "Baha"}, "powerType": "ROOT", "receivedRoleAssignments": []}, "status": "PUBLISHED", "content": "{\"type\":\"doc\",\"content\":[{\"type\":\"heading\",\"attrs\":{\"level\":1},\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"textStyle\",\"attrs\":{\"color\":\"#0a8dc1\"}},{\"type\":\"bold\"}],\"text\":\"Entretien du marbre poli : Secrets Pro Infaillibles pour une Brillance Éternelle\"}]},{\"type\":\"heading\",\"attrs\":{\"level\":2},\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Préserver l’éclat et la noblesse au fil du temps\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Sami venait d’emménager dans son nouvel appartement à Sousse. Le sol en \"},{\"type\":\"text\",\"marks\":[{\"type\":\"link\",\"attrs\":{\"href\":\"https://cobamgroup.com/?s=marbre&post_type=product\",\"target\":\"_blank\",\"rel\":\"noopener noreferrer nofollow\",\"class\":null,\"title\":null}},{\"type\":\"bold\"}],\"text\":\"marbre\"},{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\" poli était sa fierté — lumineux, élégant, et digne des plus beaux hôtels. Mais après quelques semaines, il remarqua des traces ternes près de l’entrée et une petite tache sombre près du salon. Panique ? Pas vraiment… car avec les bons gestes, le marbre retrouve sa brillance comme au premier jour.\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Chez COBAM Group, nous travaillons chaque jour avec ce matériau noble. Que ce soit dans nos showrooms ou sur les chantiers de nos clients, nous savons qu’un \"},{\"type\":\"text\",\"marks\":[{\"type\":\"link\",\"attrs\":{\"href\":\"https://cobamgroup.com/?s=marbre&post_type=product\",\"target\":\"_blank\",\"rel\":\"noopener noreferrer nofollow\",\"class\":null,\"title\":null}},{\"type\":\"bold\"}],\"text\":\"marbre\"},{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\" bien entretenu est un marbre qui traverse les années sans perdre son charme. Voici notre guide, adapté au climat et aux habitudes de vie en Tunisie.\"}]},{\"type\":\"paragraph\"},{\"type\":\"heading\",\"attrs\":{\"level\":2},\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Pourquoi le marbre poli mérite une attention particulière\"}]},{\"type\":\"table\",\"content\":[{\"type\":\"tableRow\",\"content\":[{\"type\":\"tableHeader\",\"attrs\":{\"colspan\":1,\"rowspan\":1,\"colwidth\":null},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Caractéristique\"}]}]},{\"type\":\"tableHeader\",\"attrs\":{\"colspan\":1,\"rowspan\":1,\"colwidth\":null},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Impact sur l’entretien\"}]}]}]},{\"type\":\"tableRow\",\"content\":[{\"type\":\"tableCell\",\"attrs\":{\"colspan\":1,\"rowspan\":1,\"colwidth\":null},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Structure cristalline ouverte\"}]}]},{\"type\":\"tableCell\",\"attrs\":{\"colspan\":1,\"rowspan\":1,\"colwidth\":null},\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"