 intérieur\"}]}]},{\"type\":\"listItem\",\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Planifier un polissage ou une restauration\"}]}]},{\"type\":\"listItem\",\"content\":[{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Recevoir un guide complet d’entretien en version PDF\"}]}]}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Remplissez notre formulaire en ligne pour être recontacté par un conseiller COBAM dans les 24h.\"}]},{\"type\":\"paragraph\",\"content\":[{\"type\":\"text\",\"marks\":[{\"type\":\"bold\"}],\"text\":\"Vous pouvez aussi planifier votre visite dans l’un de nos showrooms à Djerba : Voir nos adresses et horaires.\"}]}]}", "excerpt": null, "noIndex": false, "ogTitle": null, "authorId": "cmmuhzgov000040g9nxeekhj6", "noFollow": false, "tagLinks": [{"tag": {"id": 23, "name": "astuces", "slug": "astuces"}, "tagId": 23}, {"tag": {"id": 22, "name": "conseils", "slug": "conseils"}, "tagId": 22}, {"tag": {"id": 28, "name": "decoration", "slug": "decoration"}, "tagId": 28}, {"tag": {"id": 1, "name": "entretien", "slug": "entretien"}, "tagId": 1}, {"tag": {"id": 26, "name": "humidite", "slug": "humidite"}, "tagId": 26}, {"tag": {"id": 29, "name": "interieur", "slug": "interieur"}, "tagId": 29}, {"tag": {"id": 24, "name": "maison", "slug": "maison"}, "tagId": 24}, {"tag": {"id": 3, "name": "marbre", "slug": "marbre"}, "tagId": 3}, {"tag": {"id": 2, "name": "nettoyage", "slug": "nettoyage"}, "tagId": 2}, {"tag": {"id": 21, "name": "pierre", "slug": "pierre"}, "tagId": 21}, {"tag": {"id": 19, "name": "poli", "slug": "poli"}, "tagId": 19}, {"tag": {"id": 20, "name": "sol", "slug": "sol"}, "tagId": 20}, {"tag": {"id": 25, "name": "taches", "slug": "taches"}, "tagId": 25}, {"tag": {"id": 27, "name": "tunisie", "slug": "tunisie"}, "tagId": 27}], "createdAt": "2026-03-26T07:17:14.750Z", "updatedAt": 